#include<bits/stdc++.h>
using namespace std;

int main()
{
    int n;
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        int x=(i*2),y=(i*2+1);
        x%=n;
        y%=n;
        if(x==0)
        {
            x=n;
        }
        if(y==0)
        {
            y=n;
        }
        printf("%d %d\n",x,y);
    }
    return 0;
}
